import{c as o,Q as e,j as r,m as a}from"./chunks/framework.hhGiamYR.js";const c=JSON.parse('{"title":"先熟悉地狱之路——一个佛罗伦萨人关于恶的最诚实的建议","description":"","frontmatter":{"date":"2026-06-09T00:00:00.000Z","title":"先熟悉地狱之路——一个佛罗伦萨人关于恶的最诚实的建议"},"headers":[],"relativePath":"research/know-the-road-to-hell/index.md","filePath":"research/know-the-road-to-hell/index.md"}'),p={name:"research/know-the-road-to-hell/index.md"};function l(u,t,i,n,q,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<p>在1521年5月17日那天，我做了一件所有正经人都会皱眉头的事：我在如厕时给圭恰迪尼写信。</p><p>不是因为我粗鄙——虽然我确实粗鄙。而是因为在那里，在那个不受打扰的片刻，我终于有时间思量这个世界的荒谬。羊毛业行会委托我去卡尔皮，从一群托钵修士里为佛罗伦萨挑选一位布道者。我，尼科洛·马基雅维利——《君主论》的作者、被教皇列入禁书目录的嫌疑人——奉命去挑选一个教诲佛罗伦萨市民走上天堂之路的人。圭恰迪尼听到这个消息后，在回信中毫不客气地取笑了我：&quot;我们可敬的羊毛业行会理事们真有眼光，把挑选一个布道者的任务委托给您，恰如把为朋友找一个美丽贤淑的妻子的任务交给帕基耶罗托——要是他还活着的话——或萨诺君一样。&quot;</p><p>帕基耶罗托和萨诺君是谁？两个佛罗伦萨臭名昭著的同性恋者。</p><p>这就是我和弗朗切斯科之间的友谊——我们从不安慰对方，我们只管往对方伤口上撒盐，然后往上面再加一勺。</p><p>但在如厕那一刻，我回给他的，却不是玩笑。我看穿了那个玩笑，从里面抽出了一根我思考了一辈子的骨头。</p><hr><h2 id="他们会喜欢一个教诲天堂之路的布道者-而我会喜欢找一个教诲魔鬼之路的布道者" tabindex="-1">&quot;他们会喜欢一个教诲天堂之路的布道者，而我会喜欢找一个教诲魔鬼之路的布道者&quot; <a class="header-anchor" href="#他们会喜欢一个教诲天堂之路的布道者-而我会喜欢找一个教诲魔鬼之路的布道者" aria-label="Permalink to &quot;&quot;他们会喜欢一个教诲天堂之路的布道者，而我会喜欢找一个教诲魔鬼之路的布道者&quot;&quot;">​</a></h2><p>让我先给你看那句我想说了一辈子的话：</p><blockquote><p>📖 <strong>原文</strong>：书信270，尼科洛·马基雅维利致弗朗切斯科·圭恰迪尼，1521年5月17日</p><p>&quot;说实话，我知道我与她的公民们在想法上背道而驰，就像在其他事情上那样。他们会喜欢一个将要教诲他们天堂之路的布道者，而我会喜欢找一个将要教诲他们走向魔鬼之路的布道者。……我相信，上天堂的真正道路，是先熟悉下地狱的道路，以避免下地狱。&quot;</p><p>— 阅读全文：<a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">machiavelli/letters/1513-1527.md</a></p></blockquote><p>这句话被埋在一封充满恶作剧的信里：我在信的后半部分描述了如何利用圭恰迪尼的急件使者在托钵僧中间制造&quot;我被大人物垂青&quot;的假象——弩手鞠了个头低到地上的躬，每个人都像弓一样弹起来，我问他们有人说&quot;皇帝有望驾临塔兰托&quot;，他们全部张大嘴巴、手上拿着帽子站在我周围，甚至在我写信的此刻他们还围着我，看我写个不停，大为惊异。</p><p>然后我补了一句：&quot;要是他们知道我正在给您写些什么，他们会更惊异哩！&quot;</p><p>典型的马基雅维利——把最严肃的思想，塞进最荒唐的故事里。</p><p>但核心命题是极度严肃的：<strong>上天堂的真正道路，是先熟悉下地狱的道路，以避免下地狱。</strong></p><p>这不是俏皮话。这是我整个政治哲学中最激进、也是在那封信里被承认得最彻底的一条原则。</p><hr><h2 id="为什么好人必须先了解恶" tabindex="-1">为什么好人必须先了解恶 <a class="header-anchor" href="#为什么好人必须先了解恶" aria-label="Permalink to &quot;为什么好人必须先了解恶&quot;">​</a></h2><p>让我从《君主论》第十五章说起。那一章是我所有思想的地基：</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第15章</p><p>&quot;人们实际上怎样生活与人们应当怎样生活，两者差距如此之大，以致一个人要是为了应当做什么而置实际上做什么于不顾，那么他非但不能自保，反而会招致毁灭。因为一个人如果想要在所有事情上都发誓许愿以良善自持，那么，他厕身于如此之多不良善的人当中必将走向毁灭。&quot;</p><p>&quot;如果没有那些恶行，就难以挽救自己的国家的话，那么他不应当顾虑那些恶行招致的名声；因为如果我们好好考虑一下每件事情就会发现，一些事情看起来是善行（virtù），可是如果照办了就会自取灭亡，而另一些事情看起来是恶行（vizio），可是如果照办了却会给他带来安全与福祉。&quot;</p><p>— 阅读全文：<a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">machiavelli/prince/prince-cn-full.md</a></p></blockquote><p>这是一段被后世称为&quot;马基雅维利主义&quot;的文字——通常被那些从未读过我一页书的人所引用。他们漏掉了一个最关键的词：<strong>必然性</strong>。恶行只有在&quot;难以挽救自己的国家&quot;的时候才被允许——不是什么时候方便，不是什么时候有利可图。是必然。是不得不。是只有那条路可走。</p><p>但更被漏掉的，是这句话背后的认知前提：<strong>你必须先认识恶，才能判断什么时候该用恶、什么时候不该用恶。</strong></p><p>一个从不认识恶的人——一个从未踏入过地狱一步的人——在面对恶的时候只会做两件事：要么天真地被恶吞噬，要么在被吞噬之前就崩溃了。</p><hr><h2 id="必把人人设想为恶棍" tabindex="-1">&quot;必把人人设想为恶棍&quot; <a class="header-anchor" href="#必把人人设想为恶棍" aria-label="Permalink to &quot;&quot;必把人人设想为恶棍&quot;&quot;">​</a></h2><p>《论李维》第三章里有一段话，我二十年前写下来的时候，就知道有人会觉得刺眼：</p><blockquote><p>📖 <strong>原文</strong>：《论李维》第一卷第3章</p><p>&quot;探究文明生活之道的人皆已证实，史乘亦充满这类事例，即驾驭共和国并为其制定法律者，必把人人设想为恶棍，他们会不失时机地利用自己灵魂中的邪念。当邪念隐而不彰时，此一假设是从隐蔽的原因得出，因为人们既看不到相反的经验，又难以识别这种原因。但是被他们称为真理导师的时间，迟早会让真相大白于天下。&quot;</p><p>— 阅读全文：<a href="https://niflhum.top/machiavelli-library/library/machiavelli/discourses/book1/03-%E7%AC%AC%E4%B8%89%E7%AB%A0.md" target="_blank" rel="noreferrer">machiavelli/discourses/book1/03-第三章.md</a></p></blockquote><p>注意我在这里用的词不是&quot;有些人&quot;，甚至不是&quot;大多数人&quot;——而是&quot;人人&quot;。所有人在某种条件下都会作恶。这不是对人的轻蔑，而是对人的清醒。制定法律的人如果假设人性本善，他制定的法律只会保护已经善良的人，却无法防御潜伏在每个善良人身上、等待机会发作的恶。</p><p>&quot;必把人人设想为恶棍&quot;——这句话经常被引用，但很少有人注意到紧接在后面的那句：&quot;他们<strong>会不失时机地利用</strong>自己灵魂中的邪念。&quot;关键词是不失时机。恶不总是在你面前咆哮。更多的时候，它在等待合适的时机。如果你从未认真观察过别人在有机会的时候会干出什么事，你永远不会在这个世界上活过三回合。</p><hr><h2 id="从卡尔皮的厕所到整个现代世界" tabindex="-1">从卡尔皮的厕所到整个现代世界 <a class="header-anchor" href="#从卡尔皮的厕所到整个现代世界" aria-label="Permalink to &quot;从卡尔皮的厕所到整个现代世界&quot;">​</a></h2><p>回到1521年那封信。我在信的末尾写了一段话，这段话值得被单独挑出来看：</p><blockquote><p>&quot;一段时期以来，我从不说出我所相信的，也从不相信我所说的。如果某些时刻我的确讲了真话，我也会将它隐藏在众多谎言里，以至于它难以被发现。&quot;</p></blockquote><p>很多人会因此骂我是个骗子。但他们没有注意到一个细节：我说这话的对象是圭恰迪尼——一个和我一样精于此道的人。我不需要给他表演&quot;我是一个诚实的人&quot;。我选择把实话告诉他，而且恰恰是以我的方式：承认自己是一个说谎者。这本身就是一种诚实——一种只有踏进地狱之后才能获得的诚实。</p><p>我在那封信里想说的，不是&quot;让我们都去做魔鬼吧&quot;。我说的是：<strong>如果你想保护善，就不要对恶视而不见。</strong> 视而不见的善良是脆弱的善良，它一碰到真正的恶意就会碎。而踏进过地狱的人在面对恶意时，不是被吓住，而是能够辨别、能够防范、能够在必要时用恶的手段来保护善的领土。</p><p>这和一个布道者的区别在于：布道者告诉人们不要犯罪。而我会告诉人们，先看看犯罪是什么样子，看清楚，记在心里——然后你才不会在被犯罪侵袭的时候手足无措。</p><hr><h2 id="所以-回到那个问题——为什么好人必须首先熟悉恶" tabindex="-1">所以，回到那个问题——为什么好人必须首先熟悉恶？ <a class="header-anchor" href="#所以-回到那个问题——为什么好人必须首先熟悉恶" aria-label="Permalink to &quot;所以，回到那个问题——为什么好人必须首先熟悉恶？&quot;">​</a></h2><p>因为善从来不是靠无知来维持的。一个人如果从未见过恶，他对善的坚守就像一座从未经过暴风雨检验的房子：看起来很美，但一阵强风就能掀翻屋顶。而一个见识过恶、理解过恶、甚至在某些必然的时刻使用过恶的人，他对善的守护是另一种性质——他知道恶会从哪里来、恶会以什么方式出现、恶会在什么时候最危险。他不是天真地相信善，而是清醒地选择善。</p><p>我在那封信里说的话，十三年后在我的临终时刻得到了呼应。据同时代人记载，我临终前对围在床边的朋友讲了一个梦：一队衣衫褴褛的圣徒走向天堂，另一队仪表庄严的伟人——柏拉图、普鲁塔克、古代最伟大的心灵——走向地狱。我说：&quot;把我扔进地狱吧，在那里我可以跟古代伟人讨论政治。天堂属于圣徒和乞丐，地狱属于那些做事的人。&quot;</p><p>这不是亵渎。这是我整个存在方式的终极表达：<strong>熟悉地狱不是为了崇拜地狱，而是为了在地狱之上建立起不会坍塌的天堂。</strong></p><p>如果有人问起我——那个在卡尔皮的厕所里给圭恰迪尼写信的人——能给善良的人们什么最诚实的建议，我会说：不要害怕了解恶。不要以为闭上眼睛邪恶就不存在了。去看看地狱长什么样，看清它的每一条路、每一个拐角、每一种诱惑——不是为了走进去，而是为了知道怎么避开它，怎么防范它，怎么在被迫穿过它的时候不被它吞没。</p><p>问心无愧的人闭上眼睛就可以上天堂。但如果你想保护的不只是自己，如果你想保护的是一座城市、一个共和国、一份值得守护的东西——那么，我的朋友，你可能需要先睁着眼睛走一遍地狱。</p><hr><p><em>尼科洛·马基雅维利，圣卡夏诺</em></p>',43)])])}const d=o(p,[["render",l]]);export{c as __pageData,d as default};
